package arch.day38;

import java.util.*;

public class Day38Intermediate {

    enum Scope { SINGLETON, PROTOTYPE }

    static class BeanDef {
        final String name;
        final Scope scope;
        int instanceCount = 0;
        String singleton;
        BeanDef(String name, Scope scope) { this.name = name; this.scope = scope; }
    }

    // Models ObjectFactory<T> — inject this instead of T directly for prototype deps
    @FunctionalInterface
    interface Factory<T> { T get(); }

    static class MiniContainer {
        private final Map<String, BeanDef> registry = new LinkedHashMap<>();

        void register(String name, Scope scope) {
            registry.put(name, new BeanDef(name, scope));
        }

        String getBean(String name) {
            BeanDef def = registry.get(name);
            if (def.scope == Scope.SINGLETON) {
                if (def.singleton == null) {
                    def.instanceCount++;
                    def.singleton = name + "#instance-" + def.instanceCount;
                }
                return def.singleton;
            } else {
                def.instanceCount++;
                return name + "#instance-" + def.instanceCount;
            }
        }

        // Spring: ObjectFactory<T> injected into singleton; getObject() called per use
        Factory<String> getFactory(String name) {
            return () -> getBean(name);
        }
    }

    public static void main(String[] args) {
        MiniContainer c = new MiniContainer();
        c.register("userService", Scope.SINGLETON);
        c.register("requestParser", Scope.PROTOTYPE);

        // --- Scenario 1: Singleton scope ---
        System.out.println("--- Scenario 1: Singleton scope ---");
        String s1 = c.getBean("userService");
        String s2 = c.getBean("userService");
        System.out.println("First call:   " + s1);
        System.out.println("Second call:  " + s2);
        System.out.println("Same object:  " + s1.equals(s2));
        System.out.println();

        // --- Scenario 2: Prototype scope ---
        System.out.println("--- Scenario 2: Prototype scope ---");
        String p1 = c.getBean("requestParser");
        String p2 = c.getBean("requestParser");
        System.out.println("First call:   " + p1);
        System.out.println("Second call:  " + p2);
        System.out.println("Same object:  " + p1.equals(p2));
        System.out.println();

        // --- Scenario 3: Scope mismatch ---
        System.out.println("--- Scenario 3: Scope mismatch (prototype pinned in singleton) ---");
        // Spring: constructor(RequestParser parser) captures ONE prototype at startup
        String singleton = c.getBean("userService");
        String pinned = c.getBean("requestParser"); // captured once
        System.out.println("Singleton:          " + singleton);
        System.out.println("Captured prototype: " + pinned);
        System.out.println("Later call (same):  " + pinned);
        System.out.println("BUG: prototype is meant to be per-call but is pinned forever");
        System.out.println();

        // --- Scenario 4: ObjectFactory fix ---
        System.out.println("--- Scenario 4: ObjectFactory fix (new instance per call) ---");
        // Spring: inject ObjectFactory<RequestParser>, call getObject() per method
        Factory<String> factory = c.getFactory("requestParser");
        String r1 = factory.get();
        String r2 = factory.get();
        System.out.println("Factory call 1: " + r1);
        System.out.println("Factory call 2: " + r2);
        System.out.println("Same object:    " + r1.equals(r2));
        System.out.println("FIX: inject ObjectFactory<T>, call getObject() per use.");
    }
}

package arch.day38;

import java.util.*;

public class Day38Advanced {

    record BeanNode(String name, List<String> deps) {}

    static List<String> findCycle(Map<String, BeanNode> graph) {
        Set<String> visited = new HashSet<>();
        Set<String> onStack = new HashSet<>();
        List<String> path = new ArrayList<>();
        for (String bean : graph.keySet()) {
            if (!visited.contains(bean)) {
                if (dfs(bean, graph, visited, onStack, path)) {
                    return new ArrayList<>(path);
                }
            }
        }
        return Collections.emptyList();
    }

    static boolean dfs(String bean, Map<String, BeanNode> graph,
                       Set<String> visited, Set<String> onStack, List<String> path) {
        visited.add(bean);
        onStack.add(bean);
        path.add(bean);
        BeanNode node = graph.get(bean);
        if (node != null) {
            for (String dep : node.deps()) {
                if (!visited.contains(dep)) {
                    if (dfs(dep, graph, visited, onStack, path)) return true;
                } else if (onStack.contains(dep)) {
                    path.add(dep);
                    return true;
                }
            }
        }
        onStack.remove(bean);
        path.remove(path.size() - 1);
        return false;
    }

    static void analyse(String label, Map<String, BeanNode> graph) {
        System.out.println(label);
        graph.forEach((k, v) -> System.out.println("  " + k + " -> " + v.deps()));
        List<String> cycle = findCycle(graph);
        System.out.println(cycle.isEmpty()
            ? "  Result: NO CYCLE — context starts successfully."
            : "  Result: CYCLE — " + String.join(" -> ", cycle));
        System.out.println();
    }

    public static void main(String[] args) {
        // === Block 1: Graph with circular dependency ===
        System.out.println("=== Block 1: Bean graph with circular dependency ===");
        System.out.println();
        Map<String, BeanNode> before = new LinkedHashMap<>();
        before.put("OrderService",   new BeanNode("OrderService",   List.of("PaymentService")));
        before.put("PaymentService", new BeanNode("PaymentService", List.of("FraudService")));
        before.put("FraudService",   new BeanNode("FraudService",   List.of("OrderService")));
        analyse("Before refactoring:", before);

        // === Block 2: Refactored graph — shared bean extracted ===
        System.out.println("=== Block 2: After extracting shared FraudChecker ===");
        System.out.println();
        Map<String, BeanNode> after = new LinkedHashMap<>();
        after.put("OrderService",   new BeanNode("OrderService",   List.of("PaymentService", "FraudChecker")));
        after.put("PaymentService", new BeanNode("PaymentService", List.of("FraudChecker")));
        after.put("FraudChecker",   new BeanNode("FraudChecker",   Collections.emptyList()));
        analyse("After refactoring:", after);

        // === Block 3: Fix decision reference table ===
        System.out.println("=== Block 3: Circular dependency fix decision table ===");
        System.out.println();
        System.out.println("Situation                          | Fix                           | Permanent?");
        System.out.println("-----------------------------------|-------------------------------|------------");
        System.out.println("A needs B, B needs A               | Extract shared bean C         | YES");
        System.out.println("A needs B, B needs A (urgent fix)  | @Lazy on one injection point  | NO");
        System.out.println("A needs B for one method only      | Move method to B or new bean  | YES");
        System.out.println("A and B represent same concept     | Merge into one bean           | YES");
        System.out.println("A calls B only at runtime          | Inject via ApplicationContext | AVOID");
    }
}

